# ─── Color Definitions ───────────────────────────────────────
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
CYAN='\033[0;36m'
BOLD='\033[1m'
NC='\033[0m' # No Color

# ─── Trap: Reset terminal on exit/interrupt ───────────────────
trap 'tput sgr0; echo ""' EXIT INT TERM

# ─── Logging Helper ──────────────────────────────────────────
log_info()    { echo -e "${GREEN}[INFO]${NC}  $1"; }
log_warn()    { echo -e "${YELLOW}[WARN]${NC}  $1"; }
log_error()   { echo -e "${RED}[ERROR]${NC} $1"; }
log_section() { echo -e "\n${CYAN}${BOLD}══════════════════════════════════════${NC}"; echo -e "${CYAN}${BOLD}  $1${NC}"; echo -e "${CYAN}${BOLD}══════════════════════════════════════${NC}\n"; }

# ─── Root Check ──────────────────────────────────────────────
get_port_80_listener() {
    ss -tulpn 2>/dev/null | awk '/:80[[:space:]]/ && /LISTEN/ {print; exit}'
}

get_port_53_listener() {
    ss -tulpn 2>/dev/null | awk '/:53[[:space:]]/ && /LISTEN/ {print; exit}'
}

# Fungsi universal untuk memilih IP Address dari interface yang aktif
select_ip() {
    local prompt_msg="$1"
    local interfaces=()
    local line=""
    local idx=1
    local choice=""
    local selected_if=""
    local selected_ip=""

    while IFS= read -r line; do
        interfaces+=("$line")
    done < <(ip -o -4 addr show up scope global | awk '{print $2 "|" $4}')

    if [[ ${#interfaces[@]} -eq 0 ]]; then
        selected_ip="$(hostname -I | awk '{print $1}')"
        echo "$selected_ip"
        return 0
    fi

    echo -e "${CYAN}${prompt_msg}${NC}" >&2
    for line in "${interfaces[@]}"; do
        echo -e "  ${YELLOW}${idx}.${NC} ${line%%|*} -> ${line##*|}" >&2
        idx=$((idx + 1))
    done

    while true; do
        printf "\033[0;36m%s [1-%d] (default 1): \033[0m" "Pilih interface" "${#interfaces[@]}" >&2
        if ! IFS= read -r choice < /dev/tty; then
            echo "" >&2
            return 1
        fi

        if [[ -z "$choice" ]]; then
            choice=1
        fi

        if [[ "$choice" =~ ^[0-9]+$ ]] && (( choice >= 1 && choice <= ${#interfaces[@]} )); then
            selected_if="${interfaces[$((choice - 1))]}"
            selected_ip="${selected_if##*|}"
            selected_ip="${selected_ip%%/*}"
            echo "$selected_ip"
            return 0
        fi

        log_error "Pilihan interface tidak valid." >&2
    done
}

choose_access_ip() {
    APACHE_ACCESS_IP=$(select_ip "Pilih interface untuk akses Apache2:")
    [[ -n "$APACHE_ACCESS_IP" ]]
}

check_root() {
    if [[ $EUID -ne 0 ]]; then
        log_error "Script ini harus dijalankan sebagai root. Gunakan: sudo bash install.sh"
        exit 1
    fi
}

