prompt_menu_choice() {
    while true; do
        printf "\033[0;36mPilih opsi [1-8]: \033[0m"
        if ! IFS= read -r CHOICE < /dev/tty; then
            echo ""
            log_error "Gagal membaca input dari terminal."
            return 1
        fi

        case "$CHOICE" in
            [1-8])
                return 0
                ;;
            *)
                log_error "Pilihan tidak valid. Masukkan angka 1-8."
                ;;
        esac
    done
}

# ─── System Update ───────────────────────────────────────────
system_update() {
    log_section "System Update & Upgrade"
    log_info "Memperbarui daftar paket..."
    apt update -y
    log_info "Mengupgrade paket yang sudah terinstall..."
    apt upgrade -y
    log_info "Membersihkan cache paket..."
    apt autoremove -y
    apt clean
    log_info "System update selesai."
}

