# ─── vsftpd Installation ─────────────────────────────────────
install_ftp() {
    log_section "Instalasi FTP Server (vsftpd)"

    log_info "Menginstall vsftpd..."
    apt install -y vsftpd

    log_info "Membuat backup konfigurasi vsftpd..."
    cp /etc/vsftpd.conf /etc/vsftpd.conf.bak

    log_info "Mengkonfigurasi vsftpd..."
    cat > /etc/vsftpd.conf << 'FTPEOF'
# ── vsftpd Configuration - TechCorp ──
listen=YES
listen_ipv6=NO
anonymous_enable=NO
local_enable=YES
write_enable=YES
local_umask=022
dirmessage_enable=YES
use_localtime=YES
xferlog_enable=YES
connect_from_port_20=YES
chroot_local_user=YES
allow_writeable_chroot=YES
secure_chroot_dir=/var/run/vsftpd/empty
pam_service_name=vsftpd
rsa_cert_file=/etc/ssl/certs/ssl-cert-snakeoil.pem
rsa_private_key_file=/etc/ssl/private/ssl-cert-snakeoil.key
ssl_enable=NO
userlist_enable=YES
userlist_file=/etc/vsftpd.userlist
userlist_deny=NO
ftpd_banner=Welcome to TechCorp FTP Server
FTPEOF

    log_info "Membuat user FTP: admin..."
    if id "admin" &>/dev/null; then
        log_warn "User 'admin' sudah ada, melewati pembuatan user."
    else
        useradd -m -s /bin/bash admin
        echo "admin:123" | chpasswd
        log_info "User 'admin' berhasil dibuat dengan password: 123"
    fi

    log_info "Menambahkan user admin ke vsftpd userlist..."
    echo "admin" > /etc/vsftpd.userlist

    log_info "Membuat direktori FTP untuk user admin..."
    mkdir -p /home/admin/ftp/upload
    chown nobody:nogroup /home/admin/ftp
    chmod a-w /home/admin/ftp
    chown admin:admin /home/admin/ftp/upload
    chmod 755 /home/admin/ftp/upload

    log_info "Menjalankan dan mengaktifkan service vsftpd..."
    systemctl restart vsftpd
    systemctl enable vsftpd

    log_info "Mengkonfigurasi firewall untuk FTP..."
    if command -v ufw &> /dev/null; then
        ufw allow 20/tcp
        ufw allow 21/tcp
        log_info "UFW: Port 20 & 21 dibuka."
    fi

    log_info "Status vsftpd:"
    systemctl status vsftpd --no-pager | head -5
    log_info "✅ vsftpd berhasil diinstall! User: admin | Password: 123"
}

# ─── OpenSSH Installation ────────────────────────────────────
install_ssh() {
    log_section "Instalasi SSH Server (OpenSSH)"

    log_info "Menginstall openssh-server..."
    apt install -y openssh-server

    log_info "Membuat backup konfigurasi SSH..."
    cp /etc/ssh/sshd_config /etc/ssh/sshd_config.bak

    log_info "Mengkonfigurasi SSH (key-based auth, disable root login)..."
    sed -i 's/^#\?PermitRootLogin.*/PermitRootLogin no/' /etc/ssh/sshd_config
    sed -i 's/^#\?PasswordAuthentication.*/PasswordAuthentication no/' /etc/ssh/sshd_config
    sed -i 's/^#\?PubkeyAuthentication.*/PubkeyAuthentication yes/' /etc/ssh/sshd_config
    sed -i 's/^#\?AuthorizedKeysFile.*/AuthorizedKeysFile .ssh\/authorized_keys/' /etc/ssh/sshd_config
    sed -i 's/^#\?ChallengeResponseAuthentication.*/ChallengeResponseAuthentication no/' /etc/ssh/sshd_config

    log_info "Memastikan user admin ada..."
    if ! id "admin" &>/dev/null; then
        useradd -m -s /bin/bash admin
        echo "admin:123" | chpasswd
        log_info "User 'admin' dibuat."
    fi

    log_info "Membuat direktori .ssh untuk user admin..."
    mkdir -p /home/admin/.ssh
    chmod 700 /home/admin/.ssh

    log_info "Menambahkan contoh public key ke authorized_keys..."
    cat > /home/admin/.ssh/authorized_keys << 'KEYEOF'
# ── TechCorp SSH Authorized Keys ──
# Format: ssh-rsa/ssh-ed25519 <KEY> <COMMENT>
# Ganti baris di bawah dengan public key Anda yang sebenarnya
# Contoh:
# ssh-ed25519 AAAAC3NzaC1lZDI1NTE5AAAAIExamplePublicKeyReplaceWithYourActualKey admin@techcorp
ssh-rsa AAAAB3NzaC1yc2EAAAADAQABAAABgQC0ExampleKeyPlaceholder+TechCorpAdmin/ReplaceThisWithYourActualPublicKey== admin@techcorp-placeholder
KEYEOF

    chown -R admin:admin /home/admin/.ssh
    chmod 600 /home/admin/.ssh/authorized_keys

    log_info "Menjalankan dan mengaktifkan service SSH..."
    systemctl restart ssh
    systemctl enable ssh

    log_info "Mengkonfigurasi firewall untuk SSH..."
    if command -v ufw &> /dev/null; then
        ufw allow 22/tcp
        log_info "UFW: Port 22 dibuka."
    fi

    log_warn "PENTING: Ganti placeholder public key di /home/admin/.ssh/authorized_keys"
    log_warn "         dengan public key Anda yang sebenarnya sebelum login!"
    log_info "Status SSH:"
    systemctl status ssh --no-pager | head -5
    log_info "✅ OpenSSH berhasil dikonfigurasi! Key-based auth aktif, root login dinonaktifkan."
}

# ─── BIND9 DNS Installation ──────────────────────────────────
install_dns() {
    log_section "Instalasi DNS Server (BIND9)"

    log_info "Memilih interface untuk DNS Server..."
    DNS_IP=$(select_ip "Pilih interface untuk DNS Server (bind9 akan listen pada IP ini):")
    if [[ -z "$DNS_IP" ]]; then
        log_error "Gagal memilih IP address."
        return 1
    fi
    log_info "DNS Server akan menggunakan IP: $DNS_IP"

    log_info "Memasukkan domain name yang akan digunakan..."
    read -p "$(echo -e "${CYAN}Masukkan domain name (contoh: techcorp.local): ${NC}")" DOMAIN_NAME
    if [[ -z "$DOMAIN_NAME" ]]; then
        DOMAIN_NAME="techcorp.local"
        log_info "Menggunakan domain default: $DOMAIN_NAME"
    fi

    log_info "Memasukkan reverse DNS network (contoh untuk IP ${DNS_IP%%.*}.${DNS_IP#*.}.${DNS_IP%%.*.*}.0: ${DNS_IP%%.*}.${DNS_IP#*.}.${DNS_IP%%.*.*})"
    REVERSE_NET=$(echo "$DNS_IP" | awk -F. '{print $3"."$2"."$1}')
    read -p "$(echo -e "${CYAN}Masukkan reverse zone (default: ${REVERSE_NET}.in-addr.arpa): ${NC}")" REVERSE_ZONE
    if [[ -z "$REVERSE_ZONE" ]]; then
        REVERSE_ZONE="${REVERSE_NET}.in-addr.arpa"
    fi

    log_info "Menginstall BIND9..."
    apt install -y bind9 bind9utils bind9-doc dnsutils

    log_info "Mengkonfigurasi named.conf.options..."
    cat > /etc/bind/named.conf.options << OPTIONSEOF
options {
    directory "/var/cache/bind";
    listen-on port 53 { $DNS_IP; 127.0.0.1; };
    listen-on-v6 { none; };
    allow-query { any; };
    allow-transfer { none; };
    recursion yes;
    dnssec-validation auto;
    querylog yes;
    forwarders {
        8.8.8.8;
        8.8.4.4;
    };
};
OPTIONSEOF

    log_info "Membuat file zone forward untuk domain $DOMAIN_NAME..."
    cat > /etc/bind/db.$DOMAIN_NAME << FORWARDEOF
;
; BIND data file for $DOMAIN_NAME
;
\$ORIGIN $DOMAIN_NAME.
\$TTL    604800
@       IN      SOA     ns1.$DOMAIN_NAME. admin.$DOMAIN_NAME. (
                  2024010101         ; Serial
                  604800              ; Refresh
                  86400               ; Retry
                  2419200             ; Expire
                  604800 )            ; Negative Cache TTL
;
@       IN      NS      ns1.$DOMAIN_NAME.
@       IN      NS      ns2.$DOMAIN_NAME.
@       IN      A       $DNS_IP
@       IN      MX 10   mail.$DOMAIN_NAME.
;
ns1     IN      A       $DNS_IP
ns2     IN      A       $DNS_IP
www     IN      A       $DNS_IP
mail    IN      A       $DNS_IP
ftp     IN      A       $DNS_IP
admin   IN      A       $DNS_IP
;
; Additional records
*       IN      A       $DNS_IP
FORWARDEOF

    log_info "Membuat file zone reverse untuk $REVERSE_ZONE..."
    OCTET=$(echo "$DNS_IP" | awk -F. '{print $4}')
    cat > /etc/bind/db.$REVERSE_ZONE << REVERSEEOF
;
; BIND reverse data file for $REVERSE_ZONE
;
\$TTL    604800
@       IN      SOA     ns1.$DOMAIN_NAME. admin.$DOMAIN_NAME. (
                  2024010101         ; Serial
                  604800              ; Refresh
                  86400               ; Retry
                  2419200             ; Expire
                  604800 )            ; Negative Cache TTL
;
@       IN      NS      ns1.$DOMAIN_NAME.
@       IN      NS      ns2.$DOMAIN_NAME.
;
$OCTET  IN      PTR     ns1.$DOMAIN_NAME.
$OCTET  IN      PTR     $DOMAIN_NAME.
$OCTET  IN      PTR     www.$DOMAIN_NAME.
$OCTET  IN      PTR     mail.$DOMAIN_NAME.
$OCTET  IN      PTR     ftp.$DOMAIN_NAME.
REVERSEEOF

    log_info "Menambahkan zone ke named.conf.local..."
    cat >> /etc/bind/named.conf.local << LOCALEOF

// Forward zone for $DOMAIN_NAME
zone "$DOMAIN_NAME" {
    type master;
    file "/etc/bind/db.$DOMAIN_NAME";
    allow-query { any; };
};

// Reverse zone for $REVERSE_ZONE
zone "$REVERSE_ZONE" {
    type master;
    file "/etc/bind/db.$REVERSE_ZONE";
    allow-query { any; };
};
LOCALEOF

    log_info "Memeriksa konfigurasi BIND9..."
    named-checkconf
    named-checkzone $DOMAIN_NAME /etc/bind/db.$DOMAIN_NAME
    named-checkzone $REVERSE_ZONE /etc/bind/db.$REVERSE_ZONE

    PORT_53_LISTENER="$(get_port_53_listener)"
    if [[ -n "$PORT_53_LISTENER" && "$PORT_53_LISTENER" != *"named"* ]]; then
        log_error "Port 53 sudah dipakai proses lain: $PORT_53_LISTENER"
        return 1
    fi

    log_info "Menjalankan dan mengaktifkan service BIND9..."
    systemctl restart named
    systemctl enable named

    log_info "Mengkonfigurasi firewall untuk DNS..."
    if command -v ufw &> /dev/null; then
        ufw allow 53/tcp
        ufw allow 53/udp
        log_info "UFW: Port 53 (TCP/UDP) dibuka."
    fi

    log_info "Status BIND9:"
    systemctl status named --no-pager | head -5

    log_info "Testing DNS resolution..."
    dig @$DNS_IP $DOMAIN_NAME +short
    nslookup $DOMAIN_NAME 127.0.0.1

    log_info "✅ BIND9 berhasil diinstall!"
    log_info "   DNS Server IP: $DNS_IP"
    log_info "   Domain: $DOMAIN_NAME"
    log_info "   Reverse Zone: $REVERSE_ZONE"
    log_info "   NS1: ns1.$DOMAIN_NAME -> $DNS_IP"
    log_info "   NS2: ns2.$DOMAIN_NAME -> $DNS_IP"
    echo ""
    log_warn "Untuk menggunakan DNS server ini, konfigurasi client untuk menggunakan DNS $DNS_IP"
}

# ─── DHCP Server Installation ────────────────────────────────
install_dhcp() {
    log_section "Instalasi DHCP Server (ISC-DHCP-Server)"

    log_info "Memilih interface untuk DHCP Server..."
    DHCP_INTERFACE=$(select_ip "Pilih interface untuk DHCP Server (pilih interface berdasarkan IP):")
    if [[ -z "$DHCP_INTERFACE" ]]; then
        log_error "Gagal memilih interface."
        return 1
    fi
    
    # Dapatkan nama interface dari IP yang dipilih
    INTERFACE_NAME=$(ip -o -4 addr show | grep "$DHCP_INTERFACE" | awk '{print $2}')
    if [[ -z "$INTERFACE_NAME" ]]; then
        INTERFACE_NAME=$(ip -o -4 addr show | grep "$DHCP_INTERFACE" | head -1 | awk '{print $2}')
    fi
    log_info "Interface terpilih: $INTERFACE_NAME dengan IP: $DHCP_INTERFACE"

    # Hitung network dari IP
    NETWORK=$(echo "$DHCP_INTERFACE" | awk -F. '{print $1"."$2"."$3".0"}')
    log_info "Network yang terdeteksi: $NETWORK"

    log_info "Masukkan range DHCP yang akan digunakan..."
    read -p "$(echo -e "${CYAN}Start IP range (contoh: ${NETWORK%.0}.100): ${NC}")" DHCP_START
    if [[ -z "$DHCP_START" ]]; then
        DHCP_START="${NETWORK%.0}.100"
    fi
    
    read -p "$(echo -e "${CYAN}End IP range (contoh: ${NETWORK%.0}.200): ${NC}")" DHCP_END
    if [[ -z "$DHCP_END" ]]; then
        DHCP_END="${NETWORK%.0}.200"
    fi
    
    read -p "$(echo -e "${CYAN}Netmask (default: 255.255.255.0): ${NC}")" NETMASK
    if [[ -z "$NETMASK" ]]; then
        NETMASK="255.255.255.0"
    fi
    
    read -p "$(echo -e "${CYAN}Gateway (default: $DHCP_INTERFACE): ${NC}")" GATEWAY
    if [[ -z "$GATEWAY" ]]; then
        GATEWAY="$DHCP_INTERFACE"
    fi
    
    read -p "$(echo -e "${CYAN}DNS Server (default: $DHCP_INTERFACE,8.8.8.8): ${NC}")" DNS_SERVERS
    if [[ -z "$DNS_SERVERS" ]]; then
        DNS_SERVERS="$DHCP_INTERFACE,8.8.8.8"
    fi
    
    read -p "$(echo -e "${CYAN}Domain name (default: techcorp.local): ${NC}")" DHCP_DOMAIN
    if [[ -z "$DHCP_DOMAIN" ]]; then
        DHCP_DOMAIN="techcorp.local"
    fi
    
    read -p "$(echo -e "${CYAN}Lease time in seconds (default: 86400): ${NC}")" LEASE_TIME
    if [[ -z "$LEASE_TIME" ]]; then
        LEASE_TIME="86400"
    fi

    log_info "Menginstall ISC-DHCP-Server..."
    apt install -y isc-dhcp-server

    log_info "Membuat backup konfigurasi DHCP..."
    cp /etc/default/isc-dhcp-server /etc/default/isc-dhcp-server.bak
    cp /etc/dhcp/dhcpd.conf /etc/dhcp/dhcpd.conf.bak

    log_info "Mengkonfigurasi interface DHCP di /etc/default/isc-dhcp-server..."
    cat > /etc/default/isc-dhcp-server << DEFAULEOF
# Defaults for isc-dhcp-server (sourced by /etc/init.d/isc-dhcp-server)

# Path to dhcpd's config file (default: /etc/dhcp/dhcpd.conf).
DHCPD_CONF=/etc/dhcp/dhcpd.conf

# Path to dhcpd's pid file (default: /var/run/dhcpd.pid).
DHCPD_PID=/var/run/dhcpd.pid

# Additional options to start dhcpd with.
# Don't use options -cf or -pf here; use DHCPD_CONF/ DHCPD_PID instead
OPTIONS=""

# On what interfaces should the DHCP server (dhcpd) serve DHCP requests?
# Separate multiple interfaces with spaces, e.g. "eth0 eth1".
INTERFACESv4="$INTERFACE_NAME"
INTERFACESv6=""
DEFAULEOF

    log_info "Membuat konfigurasi DHCP di /etc/dhcp/dhcpd.conf..."
    cat > /etc/dhcp/dhcpd.conf << DHCPCONFEOF
# DHCP Configuration for TechCorp
# File: /etc/dhcp/dhcpd.conf

option domain-name "$DHCP_DOMAIN";
option domain-name-servers $DNS_SERVERS;
default-lease-time $LEASE_TIME;
max-lease-time $((LEASE_TIME * 2));
authoritative;

log-facility local7;

subnet $NETWORK netmask $NETMASK {
    range $DHCP_START $DHCP_END;
    option routers $GATEWAY;
    option subnet-mask $NETMASK;
    option domain-name-servers $DNS_SERVERS;
    option domain-name "$DHCP_DOMAIN";
    option broadcast-address ${NETWORK%.0}.255;
    
    # Default lease time (seconds)
    default-lease-time $LEASE_TIME;
    max-lease-time $((LEASE_TIME * 2));
}

# Static assignments example (uncomment and modify as needed)
# host client1 {
#     hardware ethernet 00:11:22:33:44:55;
#     fixed-address ${NETWORK%.0}.50;
# }
DHCPCONFEOF

    log_info "Memeriksa konfigurasi DHCP..."
    dhcpd -t -cf /etc/dhcp/dhcpd.conf

    log_info "Menjalankan dan mengaktifkan service DHCP..."
    systemctl restart isc-dhcp-server
    systemctl enable isc-dhcp-server

    log_info "Mengkonfigurasi firewall untuk DHCP..."
    if command -v ufw &> /dev/null; then
        ufw allow 67/udp
        log_info "UFW: Port 67/UDP dibuka."
    fi

    log_info "Status DHCP Server:"
    systemctl status isc-dhcp-server --no-pager | head -5

    log_info "✅ DHCP Server berhasil diinstall dan dikonfigurasi!"
    echo ""
    echo -e "${GREEN}${BOLD}  ┌─────────────────────────────────────────────────┐${NC}"
    echo -e "${GREEN}${BOLD}  │           DHCP CONFIGURATION                   │${NC}"
    echo -e "${GREEN}${BOLD}  ├─────────────────────────────────────────────────┤${NC}"
    echo -e "${GREEN}${BOLD}  │${NC}  Interface : $INTERFACE_NAME                     ${GREEN}${BOLD}│${NC}"
    echo -e "${GREEN}${BOLD}  │${NC}  Network   : $NETWORK                           ${GREEN}${BOLD}│${NC}"
    echo -e "${GREEN}${BOLD}  │${NC}  Range     : $DHCP_START - $DHCP_END            ${GREEN}${BOLD}│${NC}"
    echo -e "${GREEN}${BOLD}  │${NC}  Gateway   : $GATEWAY                           ${GREEN}${BOLD}│${NC}"
    echo -e "${GREEN}${BOLD}  │${NC}  DNS       : $DNS_SERVERS                       ${GREEN}${BOLD}│${NC}"
    echo -e "${GREEN}${BOLD}  │${NC}  Domain    : $DHCP_DOMAIN                       ${GREEN}${BOLD}│${NC}"
    echo -e "${GREEN}${BOLD}  └─────────────────────────────────────────────────┘${NC}"
    echo ""
    log_warn "Pastikan tidak ada DHCP server lain di network yang sama!"
    log_info "Untuk melihat leases: cat /var/lib/dhcp/dhcpd.leases"
}

# ─── WordPress Installation ──────────────────────────────────
install_wordpress() {
    log_section "Instalasi WordPress (Optional)"

    log_info "Menginstall dependensi WordPress (PHP, MySQL client)..."
    apt install -y php php-mysql php-curl php-gd php-mbstring php-xml php-xmlrpc \
                   php-soap php-intl php-zip libapache2-mod-php wget unzip

    log_info "Menginstall MariaDB Server..."
    apt install -y mariadb-server mariadb-client
    systemctl start mariadb
    systemctl enable mariadb

    log_info "Membuat database dan user WordPress..."
    mysql -u root << 'SQLEOF'
CREATE DATABASE IF NOT EXISTS wordpress_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE USER IF NOT EXISTS 'wp_user'@'localhost' IDENTIFIED BY 'WpTechCorp@2024';
GRANT ALL PRIVILEGES ON wordpress_db.* TO 'wp_user'@'localhost';
FLUSH PRIVILEGES;
SQLEOF
    log_info "Database 'wordpress_db' dan user 'wp_user' berhasil dibuat."

    log_info "Mendownload WordPress versi terbaru..."
    (
        cd /tmp || { log_error "Gagal pindah ke /tmp"; return 1; }
        wget -q https://wordpress.org/latest.tar.gz -O wordpress.tar.gz
        log_info "Mengekstrak WordPress..."
        tar -xzf wordpress.tar.gz
        log_info "Memindahkan WordPress ke /var/www/html/wordpress..."
        mv wordpress /var/www/html/wordpress
        rm -f wordpress.tar.gz
    )

    log_info "Mengkonfigurasi wp-config.php..."
    cp /var/www/html/wordpress/wp-config-sample.php /var/www/html/wordpress/wp-config.php
    sed -i "s/database_name_here/wordpress_db/" /var/www/html/wordpress/wp-config.php
    sed -i "s/username_here/wp_user/" /var/www/html/wordpress/wp-config.php
    sed -i "s/password_here/WpTechCorp@2024/" /var/www/html/wordpress/wp-config.php

    log_info "Mengatur permission WordPress..."
    chown -R www-data:www-data /var/www/html/wordpress
    find /var/www/html/wordpress -type d -exec chmod 755 {} \;
    find /var/www/html/wordpress -type f -exec chmod 644 {} \;

    log_info "Mengaktifkan mod_rewrite untuk Apache..."
    a2enmod rewrite

    log_info "Membuat konfigurasi Virtual Host WordPress..."
    cat > /etc/apache2/sites-available/wordpress.conf << 'APACHEEOF'
<VirtualHost *:80>
    ServerAdmin webmaster@techcorp.id
    DocumentRoot /var/www/html/wordpress
    ServerName wordpress.techcorp.local

    <Directory /var/www/html/wordpress>
        Options FollowSymLinks
        AllowOverride All
        Require all granted
    </Directory>

    ErrorLog ${APACHE_LOG_DIR}/wordpress_error.log
    CustomLog ${APACHE_LOG_DIR}/wordpress_access.log combined
</VirtualHost>
APACHEEOF

    a2ensite wordpress.conf
    systemctl restart apache2

    log_info "Membersihkan file temporary..."
    rm -f /tmp/wordpress.tar.gz

    log_info "✅ WordPress berhasil diinstall!"
    log_info "   URL: http://$(hostname -I | awk '{print $1}')/wordpress"
    log_info "   DB Name: wordpress_db | DB User: wp_user | DB Pass: WpTechCorp@2024"
    log_warn "   Segera ubah password database di wp-config.php untuk keamanan!"
}

# ─── Install All Services ────────────────────────────────────
install_all() {
    log_section "Instalasi Semua Service"
    log_info "Memulai instalasi lengkap: Apache2 + vsftpd + OpenSSH + DNS + DHCP + WordPress..."
    system_update
    install_apache
    install_ftp
    install_ssh
    install_dns
    install_dhcp
    install_wordpress
    log_section "Instalasi Selesai"
    log_info "✅ Semua service berhasil diinstall!"
    echo ""
    echo -e "${GREEN}${BOLD}  ┌─────────────────────────────────────────────────────────┐${NC}"
    echo -e "${GREEN}${BOLD}  │                 RINGKASAN INSTALASI                     │${NC}"
    echo -e "${GREEN}${BOLD}  ├─────────────────────────────────────────────────────────┤${NC}"
    echo -e "${GREEN}${BOLD}  │${NC}  🌐 Apache2  : http://$(hostname -I | awk '{print $1}')                       ${GREEN}${BOLD}│${NC}"
    echo -e "${GREEN}${BOLD}  │${NC}  📁 FTP      : ftp://$(hostname -I | awk '{print $1}') (admin/123)          ${GREEN}${BOLD}│${NC}"
    echo -e "${GREEN}${BOLD}  │${NC}  🔒 SSH      : ssh admin@$(hostname -I | awk '{print $1}')                    ${GREEN}${BOLD}│${NC}"
    echo -e "${GREEN}${BOLD}  │${NC}  🌐 DNS      : $(hostname -I | awk '{print $1}') (custom domain)           ${GREEN}${BOLD}│${NC}"
    echo -e "${GREEN}${BOLD}  │${NC}  📡 DHCP     : Interface $(ip -o -4 addr show | grep -v " lo " | head -1 | awk '{print $2}')          ${GREEN}${BOLD}│${NC}"
    echo -e "${GREEN}${BOLD}  │${NC}  📝 WordPress: http://$(hostname -I | awk '{print $1}')/wordpress          ${GREEN}${BOLD}│${NC}"
    echo -e "${GREEN}${BOLD}  └─────────────────────────────────────────────────────────┘${NC}"
}

# ─── Main Program ────────────────────────────────────────────
main() {
    check_root
    show_banner

    while true; do
        show_menu
        prompt_menu_choice || exit 1
        case $CHOICE in
            1)
                install_all
                ;;
            2)
                system_update
                install_apache
                ;;
            3)
                system_update
                install_ftp
                ;;
            4)
                system_update
                install_ssh
                ;;
            5)
                system_update
                install_dns
                ;;
            6)
                system_update
                install_dhcp
                ;;
            7)
                system_update
                install_wordpress
                ;;
            8)
                echo -e "\n${CYAN}${BOLD}Terima kasih telah menggunakan TechCorp Installer. Sampai jumpa!${NC}\n"
                tput sgr0
                exit 0
                ;;
        esac

        echo ""
        read -r -p "$(echo -e "${YELLOW}Tekan Enter untuk kembali ke menu...${NC}")" < /dev/tty
        clear
        show_banner
    done
}

# ─── Entry Point ─────────────────────────────────────────────
main "$@"